#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005

int n, T;
int f[MAXN], r[MAXN];
int max_amount;

void dfs(int u, int amount, int visited[]) {
    if (visited[u]) return;
    visited[u] = 1;
    amount += r[u];
    if (f[u] != -1) dfs(f[u], amount, visited);
    max_amount = (max_amount > amount) ? max_amount : amount;
}

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        for (int i = 0; i < n; i++) scanf("%d", &f[i]);
        for (int i = 0; i < n; i++) scanf("%d", &r[i]);
        max_amount = 0;
        int visited[MAXN] = {0};
        for (int i = 0; i < n; i++) {
            if (!visited[i]) dfs(i, 0, visited);
        }
        printf("%d\n", max_amount);
    }
    return 0;
}

