import java.util.Scanner;

public class Main {
    static final int MAXN = 100005;
    static int n, T;
    static int[] f = new int[MAXN];
    static int[] r = new int[MAXN];
    static int max_amount;

    public static void dfs(int u, int amount, boolean[] visited) {
        if (visited[u]) return;
        visited[u] = true;
        amount += r[u];
        if (f[u] != -1) dfs(f[u], amount, visited);
        max_amount = Math.max(max_amount, amount);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        T = scanner.nextInt();
        while (T-- > 0) {
            n = scanner.nextInt();
            for (int i = 0; i < n; i++) f[i] = scanner.nextInt();
            for (int i = 0; i < n; i++) r[i] = scanner.nextInt();
            max_amount = 0;
            boolean[] visited = new boolean[n];
            for (int i = 0; i < n; i++) {
                if (!visited[i]) dfs(i, 0, visited);
            }
            System.out.println(max_amount);
        }
    }
}

